#!/usr/bin/perl
use strict;
use warnings;
use DBI;
use Config::Simple;
use Carp qw(croak);

# Load database credentials from a secure configuration file
# The config file should be stored outside the web root with restricted permissions
# (chmod 600, owned by the application user)
sub load_db_config {
    my ($config_file) = @_;

    $config_file //= '/etc/legacy_app/db.conf';

    unless (-e $config_file) {
        croak "Database configuration file not found: $config_file";
    }

    # Verify file permissions are restrictive (owner read/write only)
    my $mode = (stat($config_file))[2] & 07777;
    if ($mode & 0077) {
        croak "Database configuration file has insecure permissions: "
            . sprintf("%04o", $mode)
            . ". Please set to 0600.";
    }

    my $cfg = Config::Simple->new($config_file)
        or croak "Cannot read config file: " . Config::Simple->error();

    my $db_name = $cfg->param('database.name')
        or croak "Missing 'database.name' in config";
    my $db_host = $cfg->param('database.host')
        or croak "Missing 'database.host' in config";
    my $db_user = $cfg->param('database.user')
        or croak "Missing 'database.user' in config";
    my $db_pass = $cfg->param('database.password');

    # db_pass can be empty string but must be defined
    unless (defined $db_pass) {
        croak "Missing 'database.password' in config";
    }

    my $db_port = $cfg->param('database.port') // 3306;

    return {
        name     => $db_name,
        host     => $db_host,
        port     => $db_port,
        user     => $db_user,
        password => $db_pass,
    };
}

sub get_db_connection {
    my (%args) = @_;

    my $config_file = $args{config_file};
    my $config = load_db_config($config_file);

    my $dsn = sprintf(
        "DBI:mysql:database=%s;host=%s;port=%d",
        $config->{name},
        $config->{host},
        $config->{port},
    );

    my $dbh = DBI->connect(
        $dsn,
        $config->{user},
        $config->{password},
        {
            RaiseError           => 1,
            PrintError           => 0,
            AutoCommit           => 1,
            mysql_enable_utf8mb4 => 1,
            mysql_auto_reconnect => 0,    # Handle reconnects explicitly
            mysql_ssl            => 1,    # Enforce SSL/TLS connection
            mysql_ssl_verify_server_cert => 1,
        }
    ) or croak "Database connection failed: " . DBI->errstr;

    # Set secure session variables
    $dbh->do("SET SESSION wait_timeout = 28800");
    $dbh->do("SET NAMES 'utf8mb4'");

    return $dbh;
}

sub disconnect_db {
    my ($dbh) = @_;
    if ($dbh && $dbh->ping) {
        $dbh->disconnect;
    }
    return;
}

# Example usage with parameterized queries (preventing SQL injection)
